# Splits the existing act-result.txt into per-case cache files so the
# harness can re-verify assertions against the already-captured act output.
$raw = Get-Content -Raw /home/passp/repos/compare-agent-scripting-by-language/workspaces/2026-04-17_004319/12-pr-label-assigner/powershell-opus47-1m-high/act-result.txt
$cacheDir = '/home/passp/repos/compare-agent-scripting-by-language/workspaces/2026-04-17_004319/12-pr-label-assigner/powershell-opus47-1m-high/.act-cache'
if (-not (Test-Path $cacheDir)) { New-Item -ItemType Directory -Path $cacheDir | Out-Null }

$lines = $raw -split "`r?`n"
$currentCase = $null
$inActBlock = $false
$buf = [System.Collections.Generic.List[string]]::new()

function Flush {
    param([string] $caseName, [System.Collections.Generic.List[string]] $lines, $cacheDir)
    if ($null -eq $caseName) { return }
    $output = ($lines -join "`n")
    # Extract exit code line and strip it from the buffer.
    $exit = 0
    if ($output -match 'act exit code:\s*(\d+)') { $exit = [int]$Matches[1] }
    Set-Content -Path (Join-Path $cacheDir "$caseName.txt") -Value $output
    Set-Content -Path (Join-Path $cacheDir "$caseName.exit") -Value $exit
    Write-Host "Wrote cache for case: $caseName (exit=$exit, $($lines.Count) lines)"
}

foreach ($line in $lines) {
    if ($line -match 'act push — case:\s*(\S+)') {
        Flush -caseName $currentCase -lines $buf -cacheDir $cacheDir
        $currentCase = $Matches[1]
        $buf = [System.Collections.Generic.List[string]]::new()
        $inActBlock = $false
        continue
    }
    if ($line -match '^---\s*act stdout/stderr\s*---') { $inActBlock = $true; continue }
    if ($line -match '^---\s*act exit code:') {
        # Keep the exit line in the buffer so Flush can parse it.
        $buf.Add($line)
        $inActBlock = $false
        continue
    }
    if ($inActBlock) { $buf.Add($line) }
}
Flush -caseName $currentCase -lines $buf -cacheDir $cacheDir

